import React, { useState } from 'react';
import { View, Button, Alert, Platform } from 'react-native';
import RNIap, { requestPurchase, getProducts } from 'react-native-iap';

const productIds = ['com.example.product1', 'com.example.product2'];

const PaymentModule = () => {
  const [products, setProducts] = useState([]);

  React.useEffect(() => {
    const initIAP = async () => {
      try {
        await RNIap.initConnection();
        const availableProducts = await getProducts(productIds);
        setProducts(availableProducts);
      } catch (err) {
        console.warn(err);
      }
    };

    initIAP();

    return () => {
      RNIap.endConnection();
    };
  }, []);

  const purchaseProduct = async (productId) => {
    try {
      await requestPurchase(productId);
      Alert.alert('Purchase Successful', 'Thank you for your purchase!');
    } catch (err) {
      console.warn(err);
      Alert.alert('Purchase Failed', 'Something went wrong. Please try again.');
    }
  };

  const handlePayment = () => {
    Alert.alert('Payment Feature', 'This button will trigger the payment process!');
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {products.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title}`}
          onPress={() => purchaseProduct(product.productId)}
        />
      ))}
      <Button title="Digital Wallet" onPress={handlePayment} />
    </View>
  );
};

export default PaymentModule;